int main() {
    int matrix[3][3] = {
        {15, 25, 35},
        {45, 55, 65},
        {75, 85, 95}
    };

    printf("2D Array Elements:\n");

    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            printf("%d ", matrix[i][j]);
        }
        printf("\n");
    }

    return 0;
}
```
Expected Output:

```default
2D Array Elements:
15 25 35
45 55 65
75 85 95
